import{_ as a,o as r,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"177. Saturday And Sunday Work","description":"","frontmatter":{"title":"177. Saturday And Sunday Work","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/177-saturday-and-sunday-work.md","filePath":"ebas/mental-health/support-services/preliminary/177-saturday-and-sunday-work.md"}'),n={name:"ebas/mental-health/support-services/preliminary/177-saturday-and-sunday-work.md"};function d(s,e,i,l,p,u){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_177-saturday-and-sunday-work" tabindex="-1">177. Saturday And Sunday Work <a class="header-anchor" href="#_177-saturday-and-sunday-work" aria-label="Permalink to &quot;177. Saturday And Sunday Work&quot;">​</a></h1><p><strong>177.1</strong> All rostered time of ordinary duty performed between midnight on Friday and Midnight on Sunday shall be paid for at the rate of time and one half.</p><p><strong>177.2</strong> Where the Saturday or Sunday work involves:</p><p><strong>(a)</strong> work in excess of the prescribed rostered hours, such work will be paid for at the rate of double time; and</p><p><strong>(b)</strong> work performed by a worker of broken shifts outside a spread of nine (9) hours from the time of commencing work shall be paid for at the rate of time and three- quarters; and</p><p><strong>(c)</strong> work performed by a worker of broken shifts outside a spread of twelve (12) hours from the time of commencing work shall be paid for at the rate of double time.</p><p>Plain language terms: weekend penalty, weekend loading, weekend rates.</p>',7)])])}const f=a(n,[["render",d]]);export{m as __pageData,f as default};
